import{_ as e,c as d,o as r,ae as o}from"./chunks/framework.DI6M9D4h.js";const h=JSON.parse('{"title":"Beangle Web","description":"","frontmatter":{},"headers":[],"relativePath":"web/index.md","filePath":"web/index.md"}'),l={name:"web/index.md"};function a(n,t,i,s,c,b){return r(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="beangle-web" tabindex="-1">Beangle Web <a class="header-anchor" href="#beangle-web" aria-label="Permalink to &quot;Beangle Web&quot;">​</a></h1><p>Beangle Web 是一个基于 Scala 的 Web 开发工具库，提供 Servlet 容器集成、HTTP 处理、静态资源管理等核心功能，为 Web 应用开发提供基础支持。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><p>Beangle Web 提供以下核心能力：</p><ul><li><strong>Servlet 容器集成</strong>：提供 Servlet 容器的初始化、上下文管理和过滤器链，简化 Web 应用的启动和配置</li><li><strong>HTTP 处理</strong>：支持内容协商、用户代理识别、请求处理等，提供全面的 HTTP 协议支持</li><li><strong>静态资源管理</strong>：提供静态资源的处理、缓存和路径解析，优化静态资源的加载性能</li><li><strong>安全机制</strong>：支持请求转换和安全处理，增强 Web 应用的安全性</li><li><strong>SSE 支持</strong>：提供服务器发送事件（Server-Sent Events）功能，支持服务器向客户端推送数据</li><li><strong>网络 IO</strong>：提供网络传输工具，支持文件下载和范围请求</li><li><strong>文件上传</strong>：支持 multipart/form-data 请求，处理文件上传功能</li><li><strong>URL 构建</strong>：提供 URL 构建和渲染功能，简化 URL 的生成和管理</li><li><strong>工具类</strong>：包含 Cookie、请求处理、重定向等常用 Web 工具，提高开发效率</li></ul><h2 id="文档组织" tabindex="-1">文档组织 <a class="header-anchor" href="#文档组织" aria-label="Permalink to &quot;文档组织&quot;">​</a></h2><ul><li><a href="/web/api.html">API 调用说明</a> 详细的 API 使用指南，包含所有模块的功能说明和使用示例</li></ul><h2 id="模块总览" tabindex="-1">模块总览 <a class="header-anchor" href="#模块总览" aria-label="Permalink to &quot;模块总览&quot;">​</a></h2><table class="table-api"><thead><tr><th>模块</th><th>包名</th><th>功能说明</th></tr></thead><tbody><tr><td>Context</td><td><code>org.beangle.web.servlet.context</code></td><td>Servlet 容器上下文管理</td></tr><tr><td>Filter</td><td><code>org.beangle.web.servlet.filter</code></td><td>各种过滤器实现</td></tr><tr><td>HTTP</td><td><code>org.beangle.web.servlet.http</code></td><td>HTTP 处理相关功能</td></tr><tr><td>Init</td><td><code>org.beangle.web.servlet.init</code></td><td>初始化相关类</td></tr><tr><td>Intercept</td><td><code>org.beangle.web.servlet.intercept</code></td><td>拦截器接口</td></tr><tr><td>IO</td><td><code>org.beangle.web.servlet.io</code></td><td>网络 IO 相关功能</td></tr><tr><td>Multipart</td><td><code>org.beangle.web.servlet.multipart</code></td><td>文件上传处理</td></tr><tr><td>Resource</td><td><code>org.beangle.web.servlet.resource</code></td><td>静态资源处理</td></tr><tr><td>Security</td><td><code>org.beangle.web.servlet.security</code></td><td>安全相关功能</td></tr><tr><td>Servlet</td><td><code>org.beangle.web.servlet.servlet</code></td><td>Servlet 代理</td></tr><tr><td>SSE</td><td><code>org.beangle.web.servlet.sse</code></td><td>服务器发送事件</td></tr><tr><td>URL</td><td><code>org.beangle.web.servlet.url</code></td><td>URL 构建和渲染</td></tr><tr><td>Util</td><td><code>org.beangle.web.servlet.util</code></td><td>Web 工具类</td></tr><tr><td>Socket</td><td><code>org.beangle.web.socket</code></td><td>Socket 初始化</td></tr></tbody></table>',9)])])}const u=e(l,[["render",a]]);export{h as __pageData,u as default};
